import{_ as i,o as t,c as a,ag as l}from"./chunks/framework.DLWhSH9p.js";const p=JSON.parse('{"title":"Mobile Features","description":"","frontmatter":{},"headers":[],"relativePath":"mobile/features.md","filePath":"mobile/features.md"}'),o={name:"mobile/features.md"};function r(s,e,n,d,h,u){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="mobile-features" tabindex="-1">Mobile Features <a class="header-anchor" href="#mobile-features" aria-label="Permalink to &quot;Mobile Features&quot;">​</a></h1><h2 id="ideas" tabindex="-1">Ideas <a class="header-anchor" href="#ideas" aria-label="Permalink to &quot;Ideas&quot;">​</a></h2><p>The Ideas tab mirrors the web app&#39;s Ideas panel.</p><h3 id="list-view" tabindex="-1">List View <a class="header-anchor" href="#list-view" aria-label="Permalink to &quot;List View&quot;">​</a></h3><ul><li>Pull-to-refresh</li><li>Search by title, hook, angle, or tags</li><li>Type toggle: All / Short / Long</li><li>&quot;Hide converted&quot; filter</li><li>Long-press to delete</li></ul><h3 id="create" tabindex="-1">Create <a class="header-anchor" href="#create" aria-label="Permalink to &quot;Create&quot;">​</a></h3><ul><li>Tap the <strong>+</strong> FAB (floating action button) to add a manual idea</li><li>Tap the <strong>AI</strong> FAB (pink) to generate 5 ideas with optional context</li></ul><h3 id="detail-edit" tabindex="-1">Detail / Edit <a class="header-anchor" href="#detail-edit" aria-label="Permalink to &quot;Detail / Edit&quot;">​</a></h3><ul><li>Tap any idea to view/edit title, hook, angle, type, tags</li><li><strong>Convert to Script</strong> button (green) — creates a script with all idea data</li><li><strong>View Script</strong> button — appears after conversion, links to the script</li></ul><h2 id="scripts" tabindex="-1">Scripts <a class="header-anchor" href="#scripts" aria-label="Permalink to &quot;Scripts&quot;">​</a></h2><h3 id="list-view-1" tabindex="-1">List View <a class="header-anchor" href="#list-view-1" aria-label="Permalink to &quot;List View&quot;">​</a></h3><ul><li>Status filter chips: All / Draft / Review / Final</li><li>Search by title or tags</li><li>Long-press to delete</li><li>Pull-to-refresh (updates when navigating back from editor)</li></ul><h3 id="script-detail" tabindex="-1">Script Detail <a class="header-anchor" href="#script-detail" aria-label="Permalink to &quot;Script Detail&quot;">​</a></h3><ul><li><strong>Model picker</strong> — tap to select Claude or Gemini model from bottom sheet</li><li><strong>Write / Revise / Polish</strong> buttons with selected model</li><li><strong>View / Edit</strong> toggle — markdown rendering or raw text editor</li><li><strong>Status controls</strong> — promote (draft → review → final) or demote</li><li><strong>Delete</strong> button in the toolbar</li></ul><div class="tip custom-block"><p class="custom-block-title">Model Picker</p><p>The model picker shows a shortened name (e.g., &quot;sonnet-4-6&quot; instead of &quot;claude-sonnet-4-6&quot;). Tap to open the full list.</p></div><h2 id="discover" tabindex="-1">Discover <a class="header-anchor" href="#discover" aria-label="Permalink to &quot;Discover&quot;">​</a></h2><h3 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h3><ul><li>Search bar with submit</li><li><strong>Dropdown filter pickers</strong> (not toggles): <ul><li>Sort: Relevance / Most viewed / Newest</li><li>Duration: Any / Short / Medium / Long</li><li>Channel Size: Any / &lt;1M / &lt;100K / &lt;10K / &lt;1K</li><li>Outliers: All / 5x+ / 10x+ / 50x+</li><li>Search Depth: 50 / 100 / 150 / 200</li></ul></li><li>Changing any filter immediately re-searches</li><li>Results count displayed</li></ul><h3 id="video-cards" tabindex="-1">Video Cards <a class="header-anchor" href="#video-cards" aria-label="Permalink to &quot;Video Cards&quot;">​</a></h3><ul><li>Thumbnail, title, channel name (tappable), view count, duration</li><li><strong>Save as Idea</strong> button on each card</li></ul><h3 id="channel-deep-dive" tabindex="-1">Channel Deep Dive <a class="header-anchor" href="#channel-deep-dive" aria-label="Permalink to &quot;Channel Deep Dive&quot;">​</a></h3><p>Tap a channel name to open the deep dive modal:</p><ul><li>Subscriber count, total views, video count</li><li>Avg views, upload frequency, engagement rate</li><li>Subs/day, shorts ratio, 30-day video count</li><li><strong>Estimated Earnings</strong> — monthly revenue, per-video revenue, 30-day views (based on your RPM)</li><li>Monetization badge, channel age</li><li>Recent videos list (tappable)</li></ul><h3 id="video-detail" tabindex="-1">Video Detail <a class="header-anchor" href="#video-detail" aria-label="Permalink to &quot;Video Detail&quot;">​</a></h3><p>Tap a video card to see:</p><ul><li>Full metadata (views, likes, comments, duration, date)</li><li>Description, tags, chapters</li><li><strong>View Transcript</strong> — modal with full captions</li><li><strong>Save as Idea</strong> button</li></ul><h2 id="episodes" tabindex="-1">Episodes <a class="header-anchor" href="#episodes" aria-label="Permalink to &quot;Episodes&quot;">​</a></h2><p>Browse and manage video episodes on your phone:</p><ul><li>Episode list with pipeline stage progress indicators</li><li>Tap to view episode detail with stage status (research → script → storyboard → assets → compositing → export → review → publish)</li></ul><h2 id="proposals" tabindex="-1">Proposals <a class="header-anchor" href="#proposals" aria-label="Permalink to &quot;Proposals&quot;">​</a></h2><p>Review AI-scored content proposals:</p><ul><li>List sorted by score (0-100)</li><li>Approve or reject proposals</li><li>Approved proposals convert to ideas</li></ul><h2 id="jobs" tabindex="-1">Jobs <a class="header-anchor" href="#jobs" aria-label="Permalink to &quot;Jobs&quot;">​</a></h2><p>Monitor async worker jobs in real-time:</p><ul><li>Job list with status filters (queued, running, completed, failed)</li><li>Tap for job detail with output log</li></ul><h2 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to &quot;Audio&quot;">​</a></h2><p>Full audio production on mobile:</p><ul><li>Voice track listing per script</li><li>Playback controls</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><p>Browse your downloaded resource library:</p><ul><li>File browser with type filters</li><li>Preview media files</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><ul><li><strong>Server URL</strong> — text input with <strong>Test Connection</strong> button (shows error details on failure)</li><li><strong>Channel selector</strong> — radio buttons for your channels</li><li>Connection status indicator (green dot / red dot)</li></ul>',43)])])}const b=i(o,[["render",r]]);export{p as __pageData,b as default};
